import{_ as i,o as s,c as a,a4 as t}from"./chunks/framework.CtnSHCpE.js";const u=JSON.parse('{"title":"Testing","description":"","frontmatter":{},"headers":[],"relativePath":"Guides/Testing.md","filePath":"Guides/Testing.md","lastUpdated":1760390855000}'),n={name:"Guides/Testing.md"};function o(r,e,l,p,h,c){return s(),a("div",null,[...e[0]||(e[0]=[t(`<h1 id="testing" tabindex="-1">Testing <a class="header-anchor" href="#testing" aria-label="Permalink to &quot;Testing&quot;">​</a></h1><h2 id="getting-started" tabindex="-1">Getting Started <a class="header-anchor" href="#getting-started" aria-label="Permalink to &quot;Getting Started&quot;">​</a></h2><h3 id="environment" tabindex="-1">Environment <a class="header-anchor" href="#environment" aria-label="Permalink to &quot;Environment&quot;">​</a></h3><p>The <a href="https://cicd.zopen.community" target="_blank" rel="noreferrer">zopen community CI/CD</a> pipeline uses Wazi as a Service instances to be able to build, test, and deploy ported packages to Github Releases.</p><h3 id="zopen-community-github-actions" tabindex="-1">zopen community Github Actions <a class="header-anchor" href="#zopen-community-github-actions" aria-label="Permalink to &quot;zopen community Github Actions&quot;">​</a></h3><p>zopen community ports take advantage of Github Actions to be able to build and test project changes directly on our CI/CD z/OS machines. The <a href="https://github.com/zopencommunity/meta/blob/main/.github/workflows/build_and_test.yml" target="_blank" rel="noreferrer">build and test</a> job triggers a build on Jenkins and reports the status and test results back. If the Github Action is triggered on a Pull Request, then a status check is created to represent the status of the build and test job. Is is strong recommended that you wait for a green status before merging in your approved Pull Request.</p><p>Additionally, each port has its own github workflow in place, which calls the build and test job. For example, metaport has the following <a href="https://github.com/zopencommunity/metaport/blob/main/.github/workflows/build_and_test.yml" target="_blank" rel="noreferrer">workflow</a>, which triggers the build and test job to be executed on specific events, including on opened or updated pull requests and on the comment &#39;/run tests&#39;. It also speficies which files to ignore.</p><h4 id="what-to-do-when-there-are-issues" tabindex="-1">What to do when there are issues <a class="header-anchor" href="#what-to-do-when-there-are-issues" aria-label="Permalink to &quot;What to do when there are issues&quot;">​</a></h4><p>The build and test job can sometimes fail due to environment or Jenkins related issues. For example, this issue is quite common:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>  ..........................................................Console output: </span></span>
<span class="line"><span></span></span>
<span class="line"><span>  </span></span>
<span class="line"><span>  &lt;!DOCTYPE html&gt;&lt;html&gt;&lt;head resURL=&quot;/static/475dfc94&quot; data-rooturl=&quot;&quot; data-resurl=&quot;/static/475dfc94&quot; data-extensions-available=&quot;true&quot; data-unit-test=&quot;false&quot; data-imagesurl=&quot;/static/475dfc94/images&quot; data-crumb-header=&quot;Jenkins-Crumb&quot; data-crumb-value=&quot;82483c0595e9cee14b8c260fbf3804f9ae5fc8be2543d7ffdf71e5ec968afc98&quot;&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  ...</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p>This usually occurs when the Jenkins system is overloaded.</p><p>If this is case, simply add the comment <code>/run tests</code> to your PR to trigger another build.</p><h3 id="zopen-community-jenkins-ci-cd-pipeline" tabindex="-1">zopen community Jenkins CI/CD Pipeline <a class="header-anchor" href="#zopen-community-jenkins-ci-cd-pipeline" aria-label="Permalink to &quot;zopen community Jenkins CI/CD Pipeline&quot;">​</a></h3><p>Access to the Jenkins CI/CD Pipeline is currently restricted. To be able to view/launch Jenkins CI/CD jobs, you must first log-in with your w3id (currently IBM Internal)</p><h3 id="overview-of-jenkins-ci-cd-jobs" tabindex="-1">Overview of Jenkins CI/CD jobs <a class="header-anchor" href="#overview-of-jenkins-ci-cd-jobs" aria-label="Permalink to &quot;Overview of Jenkins CI/CD jobs&quot;">​</a></h3><p>The zopen community CI/CD pipeline defines three generic Jenkins CI/CD jobs: <code>Port-Pipeline</code>, <code>Port-Build</code> and <code>Port-Publish</code>. The <em>framework</em> jobs are viewable at <a href="https://cicd.zopen.community/view/Framework/" target="_blank" rel="noreferrer">https://cicd.zopen.community/view/Framework/</a>.</p><ul><li>Port-Pipeline: This Jenkins pipeline drives the entire build, test, and deploy pipeline. It can be used by any port that is part of the <a href="https://github.com/zopencommunity/meta" target="_blank" rel="noreferrer">zopen framework</a>. It calls the following two Jenkins Jobs as part of its pipeline: <ul><li>Port-Build: This Jenkins job builds, tests, and packages the port. It runs <code>build.sh</code> from the meta framework and produces a pax.Z artifact. If any of the build, test, or package scripts fail, then the Jenkins job will result in failure.</li><li>Port-Publish: This Jenkins job consumes an artifact from <em>Port-Build</em> and publishes it into the respective repository&#39;s Github Releases page.</li></ul></li></ul><p>The implementation of these jobs is stored under the <a href="https://github.com/zopencommunity/meta/tree/main/cicd" target="_blank" rel="noreferrer">Meta repo</a>.</p><h3 id="setting-up-a-jenkins-ci-cd-job-for-your-port" tabindex="-1">Setting up a Jenkins CI/CD job for your Port <a class="header-anchor" href="#setting-up-a-jenkins-ci-cd-job-for-your-port" aria-label="Permalink to &quot;Setting up a Jenkins CI/CD job for your Port&quot;">​</a></h3><ul><li>To set up a Jenkins CI/CD Job for your port, create a <code>cicd.groovy</code> script as follows under your zopen community repository:</li></ul><div class="language-groovy vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">groovy</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">node(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;linux&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">        stage(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;Build&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) {</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">                build </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">job</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;Port-Pipeline&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">parameters</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [string(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">name</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;PORT_GITHUB_REPO&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">value</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;https://github.com/zopencommunity/myport.git&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">), string(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">name</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;PORT_DESCRIPTION&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">value</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;This is a description of my port&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> )]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">        }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p>Once you have checked in the <code>cicd.groovy</code> script, inform Igor Todorovski at <a href="mailto:itodorov@ca.ibm.com" target="_blank" rel="noreferrer">itodorov@ca.ibm.com</a> and he will create the pipeline job corresponding to your project.</p><h3 id="launch-a-jenkins-ci-cd-build-for-your-project" tabindex="-1">Launch a Jenkins CI/CD build for your project <a class="header-anchor" href="#launch-a-jenkins-ci-cd-build-for-your-project" aria-label="Permalink to &quot;Launch a Jenkins CI/CD build for your project&quot;">​</a></h3><p>If you have sufficient access, then you can launch a build of your z/OS Open Source port via Jenkins. Alternatively, you can initiate a build automatically via a commit to the corresponding repository.</p><p>If you have access, to start a build, locate your port from the <em>Port</em> view: <a href="https://cicd.zopen.community" target="_blank" rel="noreferrer">https://cicd.zopen.community</a>.</p><p>Click on the arrow pointing downwards and select <em>Build Now</em>. This will launch a build of your port.</p>`,26)])])}const k=i(n,[["render",o]]);export{u as __pageData,k as default};
